<script>
import XLSX from "xlsx"; // import xlsx
import QuotaItem from "../../components/Quota/QuotaItem.vue";
import SpinnerDialog from "../../components/UI/SpinnerDialog.vue";
import ScrollToTop from "../../components/UI/ScrollToTop.vue";
import ConfirmModal from "../../components/UI/ConfirmModal.vue";
import { isLogVisible } from "../../js/debug.js";
export default {
  components: { QuotaItem, SpinnerDialog, ScrollToTop, ConfirmModal },
  data() {
    return {
      yearNo: 4,
      error: null,
      isLoading: false,
      json: [
        { name: "Dady", age: "21" },
        { name: "Jonh", age: "25" },
        { name: "James", age: "17" },
      ],
      file: null,

      // Visible
      cancelVisible: false,
      confirmVisible: false,
    };
  },

  created() {},
  computed: {
    // subjects
    hasSubjects() {
      return this.$store.getters["subjects/hasSubjects"];
    },

    schedule() {
      return this.$store.getters["schedule"];
    },

    // get OffLink
    subjects() {
      return this.$store.getters["subjects/subjects"];
    },
    quota() {
      return this.$store.getters["quota/quota"];
    },
    reqQuota() {
      return this.$store.getters["quota/reqQuota"];
    },
    hasQuota() {
      return this.$store.getters["quota/hasQuota"];
    },
    getMaxYears() {
      return this.$store.getters["years/getMaxYears"](this.yearNo);
    },
    years() {
      return this.$store.getters["subjects/years"];
    },
    logVisible() {
      return isLogVisible();
    },
    editSuccess() {
      console.log(this.$refs.quotaItem);
      if (this.$refs.quotaItem !== undefined) {
        return this.$refs.quotaItem.editSuccess;
      } else {
        return false;
      }
    },
  },
  methods: {
    // fileUpload() {
    //   // console.log(this.$refs.file);
    //   // var XL_row_object = XLSX.utils.sheet_to_json(this.$refs.file);
    //   // console.log(XL_row_object);
    //   // var json_object = JSON.stringify(XL_row_object);
    //   // console.log(json_object);

    // },
    // fileUpload(e) {
    //   const file = e.target.files[0];
    //   console.log(file);
    //   var workbook = XLSX.read(file);
    //   console.log(workbook);
    //   var XL_row_object = XLSX.utils.sheet_to_json(workbook);
    //   console.log(XL_row_object);
    //   var json_object = JSON.stringify(XL_row_object);
    //   console.log(json_object);
    // },
    fileUpload(event) {
      this.file = event.target.files ? event.target.files[0] : null;
      if (this.file) {
        const reader = new FileReader();

        reader.onload = (e) => {
          /* Parse data */
          const bstr = e.target.result;
          const wb = XLSX.read(bstr, { type: "binary" });
          /* Get first worksheet */
          const wsname = wb.SheetNames[0];
          const ws = wb.Sheets[wsname];
          /* Convert array of arrays */
          const data = XLSX.utils.sheet_to_json(ws, { header: 1 });
          console.log(data);
        };

        reader.readAsBinaryString(this.file);
      }
    },
    onExport() {
      const dataWS = XLSX.utils.json_to_sheet(this.json);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, dataWS);
      XLSX.writeFile(wb, "export.xlsx");
    },
    async processQuota() {
      console.log("button process pressed");
      try {
        this.isLoading = true;
        await this.$store.dispatch("quota/processQuota");
        this.isLoading = false;
      } catch (e) {
        this.isLoading = false;
        this.error = e;
      }

      this.$store.dispatch("updateToast", {
        mode: "success",
        show: true,
        message: "ประมวลผลสำเร็จ ",
      });
    },

    async confirmProcess() {
      try {
        this.isLoading = true;
        await this.$store.dispatch("quota/confirmProcess");
        this.isLoading = false;

        this.$store.dispatch("updateToast", {
          mode: "success",
          show: true,
          message: "ยืนยันประมวลผลสำเร็จ ",
        });
      } catch (e) {
        this.isLoading = false;
        this.error = e;
      }
    },

    async undoProcessQuota() {
      try {
        this.isLoading = true;
        await this.$store.dispatch("quota/undoProcessQuota");
        this.isLoading = false;
      } catch (e) {
        this.isLoading = false;
        this.error = e;
      }

      this.$store.dispatch("updateToast", {
        mode: "success",
        show: true,
        message: "ยกเลิกการประมวลผลสำเร็จ ",
      });
    },
    async nextSchedule() {
      try {
        this.isLoading = true;
        await this.$store.dispatch("nextSchedule");
        this.isLoading = false;
      } catch (e) {
        this.isLoading = false;
        this.error = e;
      }
    },
    async checkQuotaStatus() {
      try {
        this.isLoading = true;
        const status = await this.$store.dispatch("quota/checkQuotaStatus");
        console.log(status);
        this.isLoading = false;
      } catch (e) {
        this.isLoading = false;
        this.error = e;
      }
    },

    closeError() {
      this.error = null;
    },
  },
};
</script>

