<script>
// import { auth } from "../../js/firebaseDb.js";
import FormValidation from "../../mixins/formValidation.js";
import DataModal from "../../components/UI/DataModal.vue";
export default {
  mixins: [FormValidation], // isNumber()
  components: { DataModal },
  data() {
    return {
      editDia1Vis: false,
      error: null,
      form1Valid: true,
      nameTitle: { val: "", isValid: true },
      firstName: { val: "", isValid: true },
      lastName: { val: "", isValid: true },
      gender: { val: "", isValid: true },
      conAddress: {
        val: "",
        isValid: true,
      },
      homAddress: {
        val: "",
        isValid: true,
      },
      tel: { val: "", isValid: true },
      email: { val: "", isValid: true },
    };
  },
  computed: {
    userInfo() {
      return this.$store.getters["userInfo"];
    },
  },
  methods: {
    closeEdit1() {
      this.editDia1Vis = false;
    },
    isForm1Valid() {},
    async submitData1() {
      // Form validation
      this.isForm1Valid();
      if (!this.form1Valid) {
        return;
      }
      await this.$store.dispatch("updateToast", {
        mode: "loading",
        show: true,
        message: "กำลังบันทึกข้อมูล",
      });
      const submittedData = {
        id: this.user.uid,
        nameTitle: this.nameTitle.val,
        firstName: this.firstName.val,
        lastName: this.lastName.val,
        gender: this.gender.val,
        conAddress: this.conAddress.val,
        homAddress: this.homAddress.val,
        tel: this.tel.val,
        email: this.email.val,
      };
      this.editDia1Vis = false;
      await this.$store.dispatch("updateUserInfo", {
        mode: "student",
        ...submittedData,
      });
      await this.$store.dispatch("clearToast");
      await this.$store.dispatch("updateToast", {
        mode: "success",
        show: true,
        message: "อัพเดตโควต้าสำเร็จ",
      });
    },
    editDia1() {
      this.nameTitle.val = this.userInfo.nameTitle;
      this.firstName.val = this.userInfo.firstName;
      this.lastName.val = this.userInfo.lastName;
      this.gender.val = this.userInfo.gender;
      this.conAddress.val = this.userInfo.conAddress;
      this.homAddress.val = this.userInfo.homAddress;
      this.tel.val = this.userInfo.tel;
      this.email.val = this.userInfo.email;
      this.editDia1Vis = true;
    },
    closeError() {
      this.error = null;
    },
  },
};
</script>

