<template>
  <!-- This is Admin Main -->
  <admin-header></admin-header>
  <div v-if="isloading">
    <base-spinner></base-spinner>
  </div>

  <router-view v-else></router-view>
  <toast
    :show="!!error"
    mode="error"
    @close="closeError"
    fixed
    :message="error"
  >
  </toast>
</template>

<script>
import LoadDataMixin from "../../mixins/loadData.js";
import AdminHeader from "../../components/layouts/Header/Admin.vue";

export default {
  components: { AdminHeader },
  data() {
    return {
      error: null,
      isloading: false,
    };
  },
  mixins: [LoadDataMixin], //loadSchedule()
  created() {
    this.isloading = true;
    this.loadSchedule();
    this.loadUser();
    this.isloading = false;
  },
  methods: {
    closeError() {
      this.error = null;
    },

    async loadUser() {
      try {
        await this.$store.dispatch("setUser", { mode: "admin" });
      } catch (e) {
        this.error = e.message;
      }
    },
  },
};
</script>
