<template>
  <h2 class="text-gray-500 font-semibold pt-5 ">
    แจ้งความจำนงรอบที่ {{ schedule.qRound }} เทอม
    {{ schedule.semester }} ปีการศึกษา {{ schedule.year }}
  </h2>
  <!-- <div class="border-solid my-6 border-b-4 border-primary-250 w-48"></div> -->
  <div
    class="border-b mt-10 mb-5 flex  text-gray-500 space-x-0 md:space-x-6 text-center"
  >
    <div
      class="px-2 pb-1 cursor-pointer"
      :class="{ 'selected-table-menu': uTable == 'add' }"
      @click="uTable = 'add'"
    >
      ตะกร้าวิชา ({{ bskQuotaNo }})
    </div>
    <div
      class="px-2 pb-1 cursor-pointer"
      :class="{ 'selected-table-menu': uTable == 'waiting' }"
      @click="uTable = 'waiting'"
    >
      รอพิจารณา ({{ pendingNo }})
    </div>
    <div
      class="px-2 pb-1 cursor-pointer"
      :class="{ 'selected-table-menu': uTable == 'result' }"
      @click="uTable = 'result'"
    >
      ผลการขอโควต้า ({{ reqQuotaResultStatusNo }})
    </div>
    <div
      class="px-2 pb-1 cursor-pointer"
      :class="{ 'selected-table-menu': uTable == 'cancel' }"
      @click="uTable = 'cancel'"
    >
      โควต้าที่ยกเลิก ({{ reqCancelQuotaNo }})
    </div>
  </div>
  <q-add-table
    v-if="uTable == 'add'"
    @to-waiting-table="uTable = 'waiting'"
    @to-result-table="uTable = 'result'"
  ></q-add-table>
  <q-waiting-table v-if="uTable == 'waiting'"></q-waiting-table>
  <q-result-table v-if="uTable == 'result'"></q-result-table>
  <q-cancel-table v-if="uTable == 'cancel'"></q-cancel-table>

  <div class="border-solid my-10 border-b-1 border-gray-300 w-full"></div>

  <h2 class="text-gray-500 font-semibold">
    ค้นหารายวิชารอบที่ {{ schedule.qRound }} เทอม
    {{ schedule.semester }} ปีการศึกษา {{ schedule.year }}
  </h2>
  <div class="border-solid my-6 border-b-4 border-primary-250 w-48"></div>

  <!-- search subject section -->
  <div class=" flex justify-center items-center" v-if="isLoading">
    <base-spinner class="my-10"></base-spinner>
  </div>
  <div v-else>
    <div class="flex items-center justify-center">
      <base-card
        class="flex flex-col md:flex-row items-center justify-center space-x-0 md:space-x-4  min-w-3/4"
      >
        <div class="mt-4 w-full md:w-40">
          <label class="block  text-sm text-gray-500 ">ศูนย์/หลักสูตร</label>
          <select class="form-control " v-model="campus">
            <!-- :disabled="!subject1.type" -->
            <option value="0" disabled>โปรดเลือก</option>
            <option value="R">รังสิต(4 ปี)</option>
            <option value="T">ท่าพระจันทร์(5 ปี)</option>
          </select>
        </div>
        <div class="mt-4 w-full md:w-auto">
          <label class="block  text-sm text-gray-500 ">ค้นหาด้วย</label>
          <select class="form-control " v-model="filterType">
            <!-- :disabled="!subject1.type" -->
            <option value="0" disabled>โปรดเลือก</option>
            <option value="subCode">รหัสวิชา</option>
            <option value="subName">ชื่อวิชา</option>
            <option value="subMajor">สาขาวิชาเอก</option>
          </select>
        </div>
        <div class="mt-4 w-full md:w-auto">
          <label class="block  text-sm text-gray-500 opacity-0 ">message</label>
          <select
            class="form-control px-1"
            v-model="filterValue"
            v-if="filterType === 'subMajor'"
          >
            <option v-for="major in majors" :value="major.id" :key="major.id">
              {{ major.code }} - {{ major.name }}
            </option>
          </select>
          <input
            class="form-control"
            type="text"
            placeholder="ค้นหา..."
            v-model="filterValue"
            v-else
          />
        </div>
      </base-card>
    </div>
    <div class="flex items-center justify-center">
      <table
        class="flex flex-row flex-no-wrap md:block md:bg-white rounded-lg overflow-hidden md:shadow-lg my-5 mx-auto w-full"
      >
        <thead class=" text-white">
          <tr
            class="bg-teal-400 flex flex-col flex-no wrap  rounded-l-lg md:rounded-none mb-2 md:mb-2 "
            :class="{ 'md:table-row': index === 0, 'md:hidden': index > 0 }"
            v-for="(q, index) in pagedQuota"
            :key="q.id"
          >
            <th class="p-3 text-left">รหัสวิชา</th>
            <th class="p-3 text-left ">ชื่อวิชา</th>
            <th class="p-3 text-left ">Section</th>
            <th class="p-3 text-left ">Group</th>
            <th class="p-3 text-left ">วันเวลา</th>
            <th class="p-3 text-left ">ผู้บรรยาย</th>
            <th class="p-2.5 text-left ">สถานะ</th>
            <th class="p-3 text-left ">จำนวน ขอ/รับ</th>
            <th class="p-3   text-left ">
              ใส่ตะกร้า
            </th>
            <th class="p-3   text-left hidden">
              ลงทะเบียน
            </th>
          </tr>
        </thead>
        <tbody class="flex-1 md:flex-none">
          <tr
            class="flex flex-col flex-no wrap md:table-row mb-2 md:mb-0 "
            v-for="q in pagedQuota"
            :key="q.id"
          >
            <td class="border-grey-light border hover:bg-gray-100 p-3">
              {{ q.subCode }}
            </td>
            <td class="border-grey-light border hover:bg-gray-100 p-3 ">
              {{ q.subName }}
            </td>
            <td class="border-grey-light border hover:bg-gray-100 p-3 py-3.5 ">
              {{ q.secId }}
            </td>
            <td class="border-grey-light border hover:bg-gray-100 p-3">
              {{ q.group }}
            </td>
            <td class="border-grey-light border hover:bg-gray-100 p-3">
              {{ q.secTime }}
            </td>
            <td class="border-grey-light border hover:bg-gray-100 p-3">
              {{ q.instName }}
            </td>
            <td class="border-grey-light border hover:bg-gray-100 p-3">
              {{ q.remark || "-" }}
            </td>
            <td class="border-grey-light border hover:bg-gray-100 p-3 ">
              {{ q[`q${schedule.qRound}Request`] || 0 }}/{{
                q[`q${schedule.qRound}Offer`]
              }}
            </td>
            <td
              class="border-grey-light border hover:bg-gray-100 p-3  text-blue-550 hover:text-blue-600 hover:font-medium cursor-pointer"
              @click="addBskQuota(q.id)"
            >
              เลือก
            </td>
          </tr>
        </tbody>
      </table>
    </div>
    <div
      class="text-xl font-bold  pb-20 text-center"
      v-if="filterdQuota.length === 0"
    >
      ไม่มีข้อมูลโควต้า
    </div>
    <div v-else class="flex justify-center py-5">
      <v-pagination
        v-model="page"
        :pages="pageCount"
        :range-size="1"
        active-color="#DCEDFF"
        @update:modelValue="updateHandler"
      />
    </div>
  </div>

  <!-- end search subject section -->

  <toast
    :show="!!error"
    mode="error"
    @close="closeError"
    fixed
    :message="error"
  >
  </toast>
  <div v-if="logVisible">
    {{ page }}
    {{ pagedQuota }}
    <hr />
    {{ quota }}
    <hr />
    userId: {{ userId }}
    <br />
    userRole: {{ userRole }}
    <br />
    userInfo: {{ userInfo }}
  </div>
</template>

<script>
import { isLogVisible } from "../../js/debug.js";
import QAddTable from "../../components/Student/QAddTable.vue";
import QWaitingTable from "../../components/Student/QWaitingTable.vue";
import QResultTable from "../../components/Student/QResultTable.vue";
import QCancelTable from "../../components/Student/QCancelTable.vue";
import VPagination from "@hennge/vue3-pagination";
import "@hennge/vue3-pagination/dist/vue3-pagination.css";
export default {
  components: {
    QAddTable,
    QWaitingTable,
    QResultTable,
    QCancelTable,
    VPagination,
  },
  data() {
    return {
      // search
      filterType: "subCode",
      filterValue: null,
      // pagedQuota: null,

      // system
      error: null,
      campus: "R",
      uTable: "add",
      page: 1,
      dataInPage: 10,
      isLoading: false,
    };
  },
  created() {
    this.isLoading = true;
    this.defaultProgram();
    this.isLoading = false;
  },
  computed: {
    userRole() {
      return this.$store.getters["userRole"];
    },
    userInfo() {
      return this.$store.getters["userInfo"];
    },
    userId() {
      return this.$store.getters["userId"];
    },

    //
    schedule() {
      return this.$store.getters["schedule"];
    },
    pagedQuota() {
      const pagedItems = this.filterdQuota.slice(
        this.page * this.dataInPage - this.dataInPage,
        this.page * this.dataInPage
      );
      return pagedItems;
    },
    pageCount() {
      const filterQCount = this.filterdQuota.length;
      return Math.ceil(filterQCount / this.dataInPage);
    },
    majors() {
      return this.$store.getters["majors/majors"];
    },
    logVisible() {
      return isLogVisible();
    },
    reqQuota() {
      return this.$store.getters["quota/fReqQuota"];
    },
    filter() {
      return {
        type: this.filterType,
        value: this.filterValue,
        campus: this.campus,
      };
    },
    quota() {
      return this.$store.getters["quota/quota"];
    },
    filterdQuota() {
      return this.$store.getters["quota/getQuotaByFilter"](this.filter);
    },
    bskQuotaNo() {
      return this.$store.getters["quota/bskQuotaNo"];
    },
    // reqQuotaNo() {
    //   return this.$store.getters["quota/reqQuotaNo"];
    // },
    pendingNo() {
      return this.$store.getters["quota/reqQuotaNoByStatus"]("pending");
    },
    reqQuotaResultStatusNo() {
      return this.$store.getters["quota/reqQuotaResultStatus"].length;
    },
    reqCancelQuotaNo() {
      return this.$store.getters["quota/getReqQuotaByResult"]("cancel").length;
    },
  },
  methods: {
    updateHandler() {},
    defaultProgram() {
      const theProgram = this.$store.getters["programs/getProgramByCode"](
        this.userInfo.program
      );
      if (theProgram) {
        this.campus = theProgram.camCode;
      }
    },
    addBskQuota(quotaId) {
      try {
        this.$store.dispatch("quota/addBskQuota", { quotaId: quotaId });
      } catch (e) {
        this.error = e.message;
      }
      this.uTable = "add";
    },
    rmBskQuota(quotaId) {
      try {
        this.$store.dispatch("quota/deleteBskQuota", { quotaId: quotaId });
      } catch (e) {
        this.error = e.message;
      }
    },
    closeError() {
      // this.formValid = true;
      this.error = null;
    },
  },
};
</script>

