<script>
export default {
  props: {
    mode: {
      type: String,
      required: true,
    },
    reqQuota: {
      required: true,
    },
  },
  data() {
    return {
      error: null,
      isLoading: false,
    };
  },
  created() {},
  methods: {
    loadData() {
      if (!this.mode === "student") {
        this.isLoading = true;
        this.loadResQuota();
        this.isLoading = false;
      }
    },
    closeError() {
      this.error = null;
    },
    getResQuotaNo() {
      if (!this.reqQuota) {
        return;
      }
      const position = this.$store.getters["quota/getResQuotaNo"]({
        quotaId: this.reqQuota.quota.id,
        reqId: this.reqQuota.id,
        reqRound: this.reqQuota.reqQutTime,
      });
      return position;
    },
    async loadResQuota(forceUpdate = false) {
      console.log("loadResQuota");
      try {
        await this.$store.dispatch("quota/setResQuota", {
          forceUpdate: forceUpdate,
        });
      } catch (e) {
        this.error = e.message;
      }
    },
  },
};
</script>

