<template>
  <div class=" flex justify-center items-center" v-if="isLoading">
    <base-spinner class="my-10"></base-spinner>
  </div>
  <div v-else>
    <div
      class="text-xl font-semibold  pb-20 text-center"
      v-if="!bskQuota || bskQuota.length === 0"
    >
      ไม่มีข้อมูลโควต้าที่คุณเลือก โปรดเลือกวิชาที่ต้องการขอโควต้า
    </div>
    <div v-else>
      <div v-if="isLogVisible">
        checkedQuota : {{ checkedQuota }} <br />
        bskQuota : {{ bskQuota }}
      </div>
      <div class="flex items-center justify-center">
        <table
          class="flex flex-row flex-no-wrap md:block md:bg-white rounded-lg overflow-hidden md:shadow-lg my-5 mx-auto w-full"
        >
          <thead class=" text-white">
            <tr
              class="bg-teal-400 flex flex-col flex-no wrap  rounded-l-lg md:rounded-none mb-2 md:mb-2 "
              :class="{ 'md:table-row': index === 0, 'md:hidden': index > 0 }"
              v-for="(q, index) in bskQuota"
              :key="q.id"
            >
              <th class="p-3 text-left">เลือก</th>
              <th class="p-3 text-left">รหัสวิชา</th>
              <th class="p-3 text-left ">ชื่อวิชา</th>
              <th class="p-3 text-left ">Section</th>
              <th class="p-3 text-left ">Group</th>
              <th class="p-3 text-left ">วันเวลา</th>
              <th class="p-3 text-left ">Campus</th>
              <th class="p-3 text-left ">ผู้บรรยาย</th>
              <th class="p-2.5 text-left ">หมายเหตุ</th>
              <th class="p-3 text-left ">จำนวน ขอ/รับ</th>
              <th class="p-3   text-left ">
                ยกเลิก
              </th>
              <th class="p-3   text-left hidden">
                ลงทะเบียน
              </th>
            </tr>
          </thead>
          <tbody class="flex-1 md:flex-none">
            <tr
              class="flex flex-col flex-no wrap md:table-row mb-2 md:mb-0 "
              v-for="q in bskQuota"
              :key="q.id"
            >
              <td
                class="border-grey-light border hover:bg-gray-100 p-3 text-center"
              >
                <input
                  type="checkbox"
                  class="form-checkbox"
                  :id="q.id"
                  :value="q.id"
                  v-model="checkedQuota"
                />
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3">
                {{ q.subCode }}
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3 ">
                {{ q.subName }}
              </td>
              <td
                class="border-grey-light border hover:bg-gray-100 p-3 py-3.5 "
              >
                {{ q.secId }}
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3">
                {{ q.group }}
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3">
                {{ q.secTime }}
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3">
                {{ q.campus }}
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3">
                {{ q.instName }}
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3">
                {{ q.remark || "-" }}
              </td>
              <td class="border-grey-light border hover:bg-gray-100 p-3 ">
                {{ q[`q${schedule.qRound}Request`] || 0 }}/{{
                  q[`q${schedule.qRound}Offer`]
                }}
              </td>
              <td
                class="border-grey-light border hover:bg-gray-100 p-3  text-red-500 hover:text-red-600 hover:font-medium cursor-pointer"
                @click="rmBskQuota(q.id)"
              >
                ยกเลิก
              </td>
            </tr>
          </tbody>
        </table>
      </div>
      <!-- {{ bskQuota }} -->
    </div>

    <div class="flex justify-center space-x-2 md:space-x-10">
      <base-button mode="gray" @click="deleteBatch()">
        <svg
          class="w-6 h-6"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
          xmlns="http://www.w3.org/2000/svg"
        >
          <path
            stroke-linecap="round"
            stroke-linejoin="round"
            stroke-width="2"
            d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
          ></path>
        </svg>
      </base-button>
      <base-button
        class="px-8 font-normal text-lg py-1.5"
        @click="submitReqQuota"
      >
        ยืนยันขอโควต้า
      </base-button>
    </div>
  </div>
  <toast
    :show="!!error"
    mode="error"
    @close="closeError"
    fixed
    :message="error"
  >
  </toast>
  <div v-if="isLogVisible" class="">
    <!-- {{ stdProgCode }} -->
    <!-- {{ programDetail }} -->
    <!-- {{ quotaMode }} -->
  </div>
  <SpinnerDialog :show="loadingDialog"></SpinnerDialog>
</template>

<script>
import LoadDataMixin from "../../mixins/loadData.js";
import SpinnerDialog from "../../components/UI/SpinnerDialog.vue";
import { isLogVisible } from "../../js/debug.js";
export default {
  emits: ["to-waiting-table", "to-result-table"],
  mixins: [LoadDataMixin], // loadReqQuota()
  components: { SpinnerDialog },
  data() {
    return {
      checkedQuota: [],
      error: null,
      formValid: true,
      errorQuota: [],
      isLoading: false,
      loadingDialog: false,
    };
  },
  computed: {
    isLogVisible() {
      return isLogVisible();
    },
    bskQuota() {
      return this.$store.getters["quota/fBskQuota"];
    },
    schedule() {
      return this.$store.getters["schedule"];
    },

    // stdProgCode() {
    //   return this.$store.getters["userInfo"].program;
    // },
    // programDetail() {
    //   return this.$store.getters["programs/getProgramByCode"](this.stdProgCode);
    // },
    quotaRound() {
      return this.$store.getters["schedule"].qRound;
    },

    // quotaMode() {
    //   return this.programDetail[`quotaMode${this.quotaRound}`];
    // },
  },
  methods: {
    async submitReqQuota() {
      this.loadingDialog = true;

      console.log("submitting ReqQuota");
      this.formValid = true;
      this.isFormValid();
      if (!this.formValid) {
        return;
      }

      if (this.checkedQuota.length === 0) {
        this.error = "โปรดเลือกโควต้าที่ต้องการยืนยันขอโควต้า";
        this.loadingDialog = false;
        return;
      }

      try {
        await this.$store.dispatch("quota/addReqQuota", {
          quotaIdArr: this.checkedQuota,
        });
      } catch (e) {
        this.error = e.message;
      }

      this.deleteBatch();
      this.checkedQuota = [];
      this.loadingDialog = false;
      // this.loadQuota();
      // this.loadReqQuota();
      // this.isLoading = false;

      await this.$store.dispatch("updateToast", {
        mode: "success",
        show: true,
        message: "บันทึกข้อมูลเสร็จสิ้น",
      });

      // if (this.quotaMode === "batch") {
      //   this.$emit("to-complete-table");
      // } else if (this.quotaMode === "transaction") {
      //   this.$emit("to-result-table");
      // }
    },
    isFormValid() {
      console.log("checking form validation");
      this.formValid = true;
      this.errorQuota = [];
      this.error = null;

      // check duplicate Quota request in add Table
      const quotaArr = [];
      for (const qId of this.checkedQuota) {
        const theQuota = this.$store.getters["quota/getQuotaById"](qId);
        quotaArr.push({ id: qId, ...theQuota });
      }

      // for (const q of quotaArr) {
      //   const matchReqQ = quotaArr.some((rq) => {
      //     if (q.id !== rq.id) {
      //       return rq.secId == q.secId || rq.offLink == q.offLink;
      //     } else {
      //       false;
      //     }
      //   });
      //   if (matchReqQ) {
      //     this.errorQuota.push(q.id);
      //     this.formValid = false;
      //   }
      // }

      // check duplicate Quota request in reqQuota
      const reqQuota = this.$store.getters["quota/reqQuotaNotCc"];

      console.log(reqQuota);

      let errMsg = "";
      // for each subject in basket
      for (const checkedQDetail of quotaArr) {
        // check if quota same quota ID OR same section OR same subject
        console.log(reqQuota);

        // check validation between basket and basket
        const countSameIdBasket = quotaArr.filter((rq) => {
          return rq.id === checkedQDetail.id;
        });
        const countSameSecBasket = quotaArr.filter((rq) => {
          return rq.secId === checkedQDetail.secId;
        });
        const countSameOffLinkBasket = quotaArr.filter((rq) => {
          return rq.offLink === checkedQDetail.offLink;
        });

        let localSameId = false;
        let localSameSec = false;
        let localSameOffLink = false;

        if (countSameIdBasket.length > 1) {
          localSameId = true;
        }

        if (countSameSecBasket.length > 1) {
          localSameSec = true;
        }
        if (countSameOffLinkBasket.length > 1) {
          localSameOffLink = true;
        }

        let sameId = false;
        let sameSec = false;
        let sameOffLink = false;

        if (!localSameId && !localSameSec && !localSameOffLink) {
          // check validation between basket and vuex
          sameId = reqQuota.some((rq) => {
            console.log(checkedQDetail.id);
            console.log(rq.quota.id);
            return rq.quota.id === checkedQDetail.id;
          });
          sameSec = reqQuota.some((rq) => {
            return rq.quota.secId == checkedQDetail.secId;
          });
          sameOffLink = reqQuota.some((rq) => {
            return rq.quota.offLink == checkedQDetail.offLink;
          });
        }

        // calulate subject amount both Vuex and Basket
        const subExceed = (reqQuota.length || 0) + (quotaArr.length || 0) > 7;

        const quotaData = this.$store.getters["quota/getQuotaById"](
          checkedQDetail.id
        );
        const subCode = quotaData.subCode;

        // Local Error
        if (localSameId || localSameOffLink) {
          this.formValid = false;
          errMsg = `ไม่สามารถขอวิชาที่ซ้ำกันได้ โปรดตรวจสอบตะกร้า และลองใหม่อีกครั้ง`;
        } else if (localSameSec) {
          this.formValid = false;
          errMsg = `ไม่สามารถขอวิชาที่ section ซ้ำกันได้ โปรดตรวจสอบตะกร้า และลองใหม่อีกครั้ง`;
        }

        // Vuex Error
        if (!localSameId && !localSameSec && !localSameOffLink) {
          if (sameId) {
            this.formValid = false;
            errMsg = errMsg + `${subCode} คุณได้ลงทะเบียนวิชานี้ไปแล้ว, `;
          } else if (sameSec) {
            this.formValid = false;
            errMsg =
              errMsg +
              `${subCode} คุณได้ลงทะเบียนวิชาอื่นใน Section นี้ไปแล้ว, `;
          } else if (sameOffLink) {
            this.formValid = false;
            errMsg = errMsg + `${subCode} คุณได้ลงทะเบียนวิชานี้ไปแล้ว, `;
          } else if (subExceed) {
            this.formValid = false;
            errMsg = errMsg + `${subCode} คุณได้ลงทะเบียนเกิน 7 วิชาแล้ว, `;
          }
        }
      }

      if (!this.formValid) {
        this.error = errMsg;
      }

      // Error Message
      // if (!this.formValid) {
      //   this.error = "วิชา ";

      //   for (const eq of this.errorQuota) {
      //     const quotaData = this.$store.getters["quota/getQuotaById"](eq);
      //     this.error = " " + this.error + quotaData.subCode + " ";
      //   }
      //   this.error =
      //     this.error +
      //     " คุณได้ทำการขอโควต้าซ้ำกับวิชาในระบบ หรือเวลาเรียนดังกล่าวคุณได้ขอโควต้าในวิชาอื่นไปแล้ว หรือคุณขอวิชาเกิน 7 วิชา";
      // }
    },
    async deleteBatch() {
      for (const q of this.checkedQuota) {
        try {
          await this.$store.dispatch("quota/deleteBskQuota", { quotaId: q });
        } catch (e) {
          this.error = e.message;
        }

        var index = this.checkedQuota.indexOf(q);

        if (index !== -1) {
          this.checkedQuota.splice(index, 1);
        }
      }
      this.checkedQuota = [];
    },
    rmBskQuota(quotaId) {
      try {
        this.$store.dispatch("quota/deleteBskQuota", { quotaId: quotaId });
      } catch (e) {
        this.error = e.message;
      }

      var index = this.checkedQuota.indexOf(quotaId);

      if (index !== -1) {
        this.checkedQuota.splice(index, 1);
      }
    },
    closeError() {
      this.formValid = true;
      this.errorQuota = [];
      this.error = null;
    },
  },
};
</script>

<style scoped>
html,
body {
  height: 100%;
}

@media (min-width: 768px) {
  table {
    display: inline-table !important;
  }

  thead tr:not(:first-child) {
    display: none;
  }
}

td:not(:last-child) {
  border-bottom: 0;
}

th:not(:last-child) {
  border-bottom: 2px solid rgba(0, 0, 0, 0.1);
}

th {
  @apply bg-brown-300 font-semibold;
}
</style>
