import { isLogVisible } from "../../../js/debug.js";
import { db } from "../../../js/firebaseDb";
import firebase from "firebase/app";
import "firebase/firestore";

export default {
    async setSchedule(context) {
        if (isLogVisible()) {
            console.log("start setSchedule");
        }

        const scheduleRef = db.collection(`schedule`);
        const scheduleDoc = await scheduleRef
            .where("isEnd", "==", false)
            .get()
            .catch((error) => {
                console.error("Error getting documents: ", error);
            });
        if (isLogVisible()) {
            console.log(scheduleDoc);
        }
        if (scheduleDoc.empty) {
            const error = new Error("No such document!");
            console.error(error);
            throw error;
        }

        const scheduleArr = scheduleDoc.docs.map((doc) => {
            return {
                ...doc.data(),
                id: doc.id,
            };
        });

        if (scheduleArr.length > 1) {
            console.error("matched schedule exceed 1 ");
            return;
        }

        const theSchedule = scheduleArr[0];
        console.log(theSchedule);
        context.commit("setSchedule", theSchedule);
    },

    // async addSchedule(context) {
    //     console.log(context);
    // },
    async nextSchedule(context) {
        // const isQuotaOk = await context.dispatch("quota/checkQuotaStatus", null, {
        //     root: true,
        // });

        // if (!isQuotaOk.status) {
        //     console.error(isQuotaOk);
        //     throw Error(
        //         `Some Quota was not processed : ${JSON.stringify(isQuotaOk)}`
        //     );
        // }
        const schedule = context.getters.schedule;
        const oldId = schedule.id;
        const newSchedule = {
            ...schedule,
        };
        let nextOk = false;

        // check Round
        if (schedule.qRound < 3) {
            newSchedule["qRound"] = newSchedule["qRound"] + 1;
            nextOk = true;
        }

        // check Semester
        if (schedule.semester < 3 && !nextOk) {
            newSchedule["semester"] = newSchedule["semester"] + 1;
            newSchedule["qRound"] = 1;
            nextOk = true;
        }

        // check Year
        if (!nextOk) {
            newSchedule["year"] = newSchedule["year"] + 1;
            newSchedule["semester"] = 1;
            newSchedule["qRound"] = 1;
            nextOk = true;
        }

        // update by & update time & delete old id
        console.log(context.getters.userId);
        newSchedule["updateBy"] = context.getters.userId;
        newSchedule["updateTime"] = firebase.firestore.FieldValue.serverTimestamp();
        delete newSchedule.id;

        const batch = db.batch();

        // update is end
        console.log(oldId);
        const oldScheduleRef = db.collection(`schedule`).doc(oldId);
        // await oldScheduleRef.update({ isEnd: true }).catch((error) => {
        //     throw console.error("Error updating document: ", error);
        // });
        batch.update(oldScheduleRef, { isEnd: true });

        // update in Firestore
        console.log(newSchedule);
        const newScheduleRef = db.collection(`schedule`).doc();
        // await newScheduleRef.set(newSchedule).catch((error) => {
        //     throw console.error("Error updating document: ", error);
        // });
        batch.set(newScheduleRef, newSchedule);

        await batch.commit().catch((error) => {
            throw console.error("Error updating document: ", error);
        });

        // update to vuex
        newSchedule["id"] = newScheduleRef.id;
        context.commit("setSchedule", newSchedule);
    },
};