<template>
  <tr class="text-center" v-for="(sec, index) in secList" :key="sec.id">
    <!-- first row -->
    <td class="px-1" v-if="index === 0">
      <div v-if="MaxYearsList[0]">{{ getSubCode(MaxYearsList[0].name) }}</div>
    </td>
    <td class="px-1" v-if="index === 0">
      <div v-if="MaxYearsList[1]">{{ getSubCode(MaxYearsList[1].name) }}</div>
    </td>
    <td class="px-1" v-if="index === 0">
      <div v-if="MaxYearsList[2]">{{ getSubCode(MaxYearsList[2].name) }}</div>
    </td>
    <td class="px-1" v-if="index === 0">
      <div v-if="MaxYearsList[3]">{{ getSubCode(MaxYearsList[3].name) }}</div>
    </td>

    <!-- second row -->
    <td class="px-1" colspan="4" v-if="index === 1">
      {{ LastSubject.name }}
    </td>

    <td class="px-1" colspan="4" v-if="index > 1"></td>

    <td class="px-1">{{ sec.secId }}</td>
    <td class="px-1">{{ sec.group }}</td>
    <!-- round 1 -->
    <td class="px-1">{{ sec.q1Offer >= 0 ? sec.q1Offer : "-" }}</td>
    <td
      class="px-1"
      :class="{ 'text-red-500 font-bold': sec.q1Request > sec.q1Offer }"
    >
      {{ sec.q1Request >= 0 ? sec.q1Request : "-" }}
    </td>
    <td class="px-1">{{ sec.q1Accept >= 0 ? sec.q1Accept : "-" }}</td>
    <!-- round 2 -->
    <td class="px-1">{{ sec.q2Offer >= 0 ? sec.q2Offer : "-" }}</td>
    <td
      class="px-1"
      :class="{ 'text-red-500 font-bold': sec.q2Request > sec.q2Offer }"
    >
      {{ sec.q2Request >= 0 ? sec.q2Request : "-" }}
    </td>
    <td class="px-1">{{ sec.q2Accept >= 0 ? sec.q2Accept : "-" }}</td>
    <!-- round 3 -->
    <td class="px-1">{{ sec.q3Offer >= 0 ? sec.q3Offer : "-" }}</td>
    <td
      class="px-1"
      :class="{ 'text-red-500 font-bold': sec.q3Request > sec.q3Offer }"
    >
      {{ sec.q3Request >= 0 ? sec.q3Request : "-" }}
    </td>
    <td class="px-1">{{ sec.q3Accept >= 0 ? sec.q3Accept : "-" }}</td>

    <td class="px-1">{{ sumNumber(sec.q1Accept, sec.q2Accept) }}</td>
    <td class="px-1">{{ sec.regNo >= 0 ? sec.regNo : "-" }}</td>
    <td class="px-1">{{ sumNumber(sec.regNo, sec.q3Accept) }}</td>
    <td class="px-1 ">
      <div class="inline overflow-hidden whitespace-nowrap">
        <div v-if="getInstName(sec.instId).fullName.length < 16">
          {{ getInstName(sec.instId).fullName }}
        </div>
        <div v-else>
          {{ getInstName(sec.instId).fullName.substring(0, 16) + ".." }}
        </div>
      </div>
    </td>
    <td class="px-1">
      {{ !!sec.remark ? sec.remark : "-" }}
    </td>
    <td class="px-1">
      {{ !!sec.condition ? sec.condition : "-" }}
    </td>
    <td>
      <router-link
        :to="{ name: 'quota-sec', params: { id: sec.id } }"
        v-if="secDetail"
      >
        <base-button class="mx-auto" mode="flat">Detail </base-button>
      </router-link>

      <base-button class="mx-auto" mode="flat" @click="editQuota(sec.id)" v-else
        >แก้ไข</base-button
      >
    </td>
  </tr>
  <tr v-html="secondRow"></tr>
  <tr>
    <td v-for="index in 22" :key="index" class="py-5"></td>
  </tr>
</template>

<script>
export default {
  emits: ["edit"],
  props: {
    offLink: {
      required: true,
    },
    yearNo: {
      required: true,
    },
    secDetail: {
      require: false,
      default: false,
    },
  },
  computed: {
    secondRow() {
      if (this.secList.length === 1) {
        return (
          '<td class="px-1 text-center" colspan="4" v-if="index === 1">' +
          this.LastSubject.name +
          "</td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>" +
          "<td></td>"
        );
      } else {
        return "";
      }
    },
    secList() {
      return this.$store.getters["quota/getQuotaByOffLink"](this.offLink);
    },
    MaxYearsList() {
      return this.$store.getters["years/getMaxYears"](this.yearNo);
    },
    LastSubject() {
      return this.$store.getters["subjects/getLastSubjectByOffLink"](
        this.offLink
      );
    },
  },
  methods: {
    editQuota(quotaId) {
      console.log(quotaId);
      this.$emit("edit", quotaId, this.offLink);
    },
    sumNumber(n1, n2) {
      const num1 = parseInt(n1);
      const num2 = parseInt(n2);

      if (num1 >= 0 && num2 >= 0) {
        return num1 + num2;
      } else if (num1 >= 0) {
        return num1;
      } else if (num2 >= 0) {
        return num2;
      } else {
        return "-";
      }
    },
    getSubCode(year) {
      const sub = this.$store.getters["subjects/getSubjectByYearAndOffLink"]({
        year: year,
        offLink: this.offLink,
      });
      if (sub) {
        return sub.code;
      } else {
        return "-";
      }
    },
    getInstName(instId) {
      return this.$store.getters["instructors/getNameById"](instId);
    },
  },
};
</script>

