      cfPassword: null,
      email: null,
      pickedMajor: [],
      nameTitle: null,
      firstName: null,
      lastName: null,
      gender: null,
      role: null,
    };
  },
  computed: {
    majors() {
      return this.$store.getters["majors/majors"];
    },
  },
  methods: {
    stdSignUp() {
      // check validation
      // this.v$.$touch();
      // if (this.v$.$error) return;

      // actually submit form
      auth
        .createUserWithEmailAndPassword(this.email, this.password)
        .then(async (cred) => {
          await db
            .collection("students")
            .doc(cred.user.uid)
            .set({
              username: this.username,
              password: this.password,
              cfPassword: this.cfPassword,
              email: this.email,
              major: this.pickedMajor,
              nameTitle: this.nameTitle,
              firstName: this.firstName,
              lastName: this.lastName,
              gender: this.gender,
              role: this.role,
              regDate: firebase.firestore.FieldValue.serverTimestamp(),
            });
        })
        .catch((error) => {
          this.error = `${error.code} : ${error.message}`;
        });
    },
    closeStaffDia() {
      this.editStaffVisible = false;
    },
    trydeleteStaff() {
      alert("staff is deleted");
    },
    submitData() {
