<template>
  <div class=" flex justify-center items-center" v-if="loadingData">
    <base-spinner class="my-10"></base-spinner>
  </div>
  <div class="flex items-center justify-center" v-else>
    <div
      class="text-xl font-semibold  pb-20 text-center"
      v-if="!reqQuotaResultStatus || reqQuotaResultStatus.length === 0"
    >
      ไม่มีข้อมูลโควต้าที่ต้องแสดง
    </div>
    <table
      v-else
      class="flex flex-row flex-no-wrap md:block md:bg-white rounded-lg overflow-hidden md:shadow-lg my-5 mx-auto w-full"
    >
      <thead class=" text-white">
        <tr
          class="bg-teal-400 flex flex-col flex-no wrap  rounded-l-lg md:rounded-none mb-2 md:mb-2 "
          :class="{ 'md:table-row': index === 0, 'md:hidden': index > 0 }"
          v-for="(q, index) in reqQuotaResultStatus"
          :key="q.id"
        >
          <th class="p-3 text-left">รหัสวิชา</th>
          <th class="p-3 text-left ">ชื่อวิชา</th>
          <th class="p-3 text-left ">Section</th>
          <th class="p-3 text-left ">Group</th>
          <th class="p-3 text-left ">วันเวลา</th>
          <th class="p-3 text-left ">Campus</th>
          <th class="p-3 text-left ">ผู้บรรยาย</th>
          <th class="p-3 text-left ">รอบ</th>
          <th class="p-2.5 text-left ">ผลขอโควต้า</th>
          <th class="p-3   text-left">
            ยกเลิก
          </th>
          <th class="p-3   text-left hidden">
            ผลขอโควต้า
          </th>
        </tr>
      </thead>
      <tbody class="flex-1 md:flex-none">
        <tr
          class="flex flex-col flex-no wrap md:table-row mb-2 md:mb-0 "
          v-for="q in reqQuotaResultStatus"
          :key="q.id"
        >
          <td class="border-grey-light border hover:bg-gray-100 p-3">
            {{ q.quota.subCode }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3 ">
            {{ q.quota.subName }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3 py-3.5 ">
            {{ q.quota.secId }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3">
            {{ q.quota.group }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3">
            {{ q.quota.secTime }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3">
            {{ q.quota.campus }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3">
            {{ q.quota.instName }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3">
            {{ q.reqQutTime }}
          </td>
          <td class="border-grey-light border hover:bg-gray-100 p-3">
            <ResultIcon :reqQuota="q" mode="student"></ResultIcon>
          </td>
          <td
            class="border-grey-light border hover:bg-gray-100 p-3  text-red-500 hover:text-red-600 hover:font-medium cursor-pointer"
            @click="ccReqQuota(q.quota.id, q.id)"
          >
            ยกเลิก
          </td>
        </tr>
      </tbody>
    </table>
  </div>
  <div v-if="isLogVisible">Reserve Quota : {{ resQuota }}</div>
  <SpinnerDialog :show="loadingDialog"></SpinnerDialog>
</template>
<script>
import { isLogVisible } from "../../js/debug.js";
import ResultIcon from "../UI/ResultIcon.vue";
import SpinnerDialog from "../../components/UI/SpinnerDialog.vue";
export default {
  components: { ResultIcon, SpinnerDialog },
  data() {
    return {
      loadingData: false,
      loadingDialog: false,
    };
  },
  computed: {
    isLogVisible() {
      return isLogVisible();
    },
    reqQuotaResultStatus() {
      return this.$store.getters["quota/reqQuotaResultStatus"];
    },
    reserveReqQuota() {
      return this.$store.getters["quota/getReqQuotaByResult"]("reserve");
    },
    resQuota() {
      return this.$store.getters["resQuota"];
    },
  },
  created() {},
  methods: {
    async ccReqQuota(quotaId, quotaReqId) {
      this.loadingDialog = true;
      try {
        await this.$store.dispatch("quota/cancelReqQuota", {
          quotaId: quotaId,
          quotaReqId: quotaReqId,
        });
      } catch (e) {
        this.error = e.message;
      }
      this.loadingDialog = false;
    },
  },
};
</script>

<style scoped>
html,
body {
  height: 100%;
}

@media (min-width: 768px) {
  table {
    display: inline-table !important;
  }

  thead tr:not(:first-child) {
    display: none;
  }
}

td:not(:last-child) {
  border-bottom: 0;
}

th:not(:last-child) {
  border-bottom: 2px solid rgba(0, 0, 0, 0.1);
}

th {
  @apply bg-brown-300 font-semibold;
}
</style>
