<script>
import AlertCard from "../../components/UI/AlertCard.vue";
import { db } from "../../js/firebaseDb.js";
import DataModal from "../../components/UI/DataModal.vue";
import SpinnerDialog from "../../components/UI/SpinnerDialog.vue";
import ResultIcon from "../../components/UI/ResultIcon.vue";
import { isLogVisible } from "../../js/debug.js";
import { sortText } from "../../js/utility.js";

export default {
  components: { SpinnerDialog, DataModal, ResultIcon, AlertCard },
  props: ["id"],
  data() {
    return {
      checkedReq: [],
      error: null,
      isLoading: false,
      dialogLoading: false,

      yearNo: 4,
      stdInfo: null,
      selectedRound: 1,

      stdCode: {
        val: null,
        isValid: true,
      },
      formValid: false,

      addReqVisible: false,
      addStdLoading: false,
      // quotaId: "nwzca3jxEbstJbFBZ1KM",
    };
  },
  created() {
    this.loadData();
    this.setRound();
  },
  computed: {
    logVisible() {
      return isLogVisible();
    },
    schedule() {
      return this.$store.getters["schedule"];
    },
    presentRound() {
      return this.schedule.qRound;
    },
    quotaInfo() {
      return this.$store.getters["quota/getQuotaById"](this.id);
    },
    reqQuota() {
      const allReqQuota = this.$store.getters["quota/reqQuota"];
      const filteredReq = allReqQuota.filter(
        (q) => q.reqQutTime === this.selectedRound
      );
      return sortText(filteredReq, "stdCode");
    },
    students() {
      return this.$store.getters["students/students"];
    },
    LastSubject() {
      return this.$store.getters["subjects/getLastSubjectByOffLink"](
        this.quotaInfo.offLink
      );
    },
    MaxYearsList() {
      return this.$store.getters["years/getMaxYears"](this.yearNo);
    },
    subName() {
      return this.LastSubject.name;
    },
    subCode() {
      return (
        " (" +
        this.getSubCode(this.MaxYearsList[0].name) +
        ", " +
        this.getSubCode(this.MaxYearsList[1].name) +
        ", " +
        this.getSubCode(this.MaxYearsList[2].name) +
        ", " +
        this.getSubCode(this.MaxYearsList[3].name) +
        ")"
      );
    },
    checkExceedReq() {
      // const acpReqQuota = this.$store.getters["quota/getReqQuotaByResult"](
      //   "accept"
      // ).length;
      const requestQuota = this.quotaInfo[`q${this.presentRound}Request`];

      const offerQuota = this.quotaInfo[`q${this.presentRound}Offer`];

      return {
        status: requestQuota < offerQuota,
        qOffer: offerQuota,
        qRequest: requestQuota,
      };
    },
  },
  methods: {
    isRound(no, targetNo) {
      return targetNo === no;
    },
    setRound() {
      this.selectedRound = this.schedule.qRound;
    },
    async addStd() {
      this.formValid = true;
      this.stdCode.isValid = true;

      this.findStd();
      if (!this.formValid || !this.stdCode.isValid) {
        this.error = "student id not found";
        return;
      }
      this.addStdLoading = true;
      try {
        await this.$store.dispatch("quota/addReqQuotaByAdmin", {
          stdInfo: this.stdInfo,
          quotaId: this.id,
          result: "accept",
        });
      } catch (e) {
        this.error = e.message;
        return;
      }
      this.$store.dispatch("updateToast", {
        mode: "success",
        show: true,
        message: "เพิ่มนักศึกษาสำเร็จ",
      });
      this.addReqVisible = false;
      this.addStdLoading = false;
      this.stdInfo = null;
      this.stdCode.val = null;
    },

    async findStd() {
      this.addStdLoading = true;
      const stdRef = db.collection("students");
      const snapshot = await stdRef
        .where("stdCode", "==", this.stdCode.val)
        .get()
        .catch((error) => {
          this.addStdLoading = false;
          this.stdCode.isValid = false;
          this.formValid = false;
          console.error("Error getting documents: ", error);
          this.error = error;
        });

      if (snapshot.empty) {
        this.addStdLoading = false;
        this.stdCode.isValid = false;
        this.formValid = false;
        this.error = "ไม่พบรหัสนักศึกษาในฐานข้อมูล";
        return;
      }
      snapshot.forEach((doc) => {
        this.stdInfo = doc.data();
        this.stdInfo.id = doc.id;
      });
      this.addStdLoading = false;
      this.stdCode.isValid = true;
      this.formValid = true;
    },
    closeAddReqDia() {
      this.addReqVisible = false;
    },
    getSubCode(year) {
      const sub = this.$store.getters["subjects/getSubjectByYearAndOffLink"]({
        year: year,
        offLink: this.quotaInfo.offLink,
      });
      if (sub) {
        return sub.code;
      } else {
        return "-";
      }
    },
    closeError() {
      this.error = null;
    },
    getMajor(majorId) {
      return this.$store.getters["majors/getMajorById"](majorId);
    },
    async loadData() {
      this.isLoading = true;
      await this.loadReqQuota();
      this.isLoading = false;
    },

    async loadReqQuota() {
      try {
        await this.$store.dispatch("quota/setReqQuotaByQuota", {
          quotaId: this.id,
        });
      } catch (e) {
        this.error = e.message;
      }
    },
    async submitResult(type) {
      this.dialogLoading = true;
      if (type !== "accept" && type !== "reject" && type !== "delete") {
        this.error = "your selected result doesn't support";
        this.dialogLoading = false;
        return;
      }

      try {
        await this.$store.dispatch("quota/updateReqQuotaBatch", {
          quotaId: this.id,
          field: "result",
          value: type,
          reqArr: this.checkedReq,
        });
      } catch (e) {
        this.error = e;
        this.dialogLoading = false;
        return;
      }

      this.$store.dispatch("updateToast", {
        mode: "success",
        message: "เปลี่ยนแปลงข้อมูลเสร็จสิ้น",
        show: true,
      });
      this.checkedReq = [];
      this.dialogLoading = false;
    },
  },
};
</script>

