<template>
  <!-- This is an example component -->
  <div class="h-screen font-kanit login bg-cover">
    <div
      class="container mx-auto h-full flex flex-1 justify-center items-center"
    >
      <div class="w-full max-w-lg">
        <div class="flex justify-center">
          <form
            class="w-11/12 sm:w-4/5  m-4 p-10 bg-white bg-opacity-90 rounded shadow-xl"
          >
            <p class="text-gray-500 font-medium text-center text-xl ">
              เข้าสู่ระบบสำหรับเจ้าหน้าที่
            </p>
            <div class="mt-4">
              <label class="block text-sm text-gray-500 " for="Username"
                >Username</label
              >
              <input
                class="form-control"
                type="email"
                id="email"
                placeholder="Username"
                v-model="username.val"
                required
              />
            </div>
            <div class="mt-4">
              <label class="block  text-sm text-gray-500 ">Password</label>
              <input
                class="form-control"
                type="password"
                id="password"
                placeholder="Password"
                v-model="password.val"
                required
              />
            </div>

            <div class="my-8 items-center flex justify-center">
              <base-button
                type="submit"
                class="px-8 font-normal text-xl py-1.5"
                @click.prevent="adminLogin()"
              >
                Login
              </base-button>
            </div>
            <div class="flex justify-center ">
              <div class="border-solid  border-b-1 border-gray-300 w-2/3"></div>
            </div>

            <div
              class="flex pt-2 space-x-4 justify-center font-light text-sm text-blue-550"
            >
              <router-link :to="{ name: 'forget-password' }">
                <p>ลืมรหัสผ่าน</p>
              </router-link>
            </div>
          </form>
        </div>
      </div>
    </div>
  </div>
  <toast
    :show="!!error"
    mode="error"
    :duration="5000"
    @close="closeError"
    :message="error"
  >
  </toast>
  <spinner-dialog :show="isLoading"></spinner-dialog>
</template>
<script>
import { db, auth } from "../../js/firebaseDb.js";
import SpinnerDialog from "../../components/UI/SpinnerDialog.vue";
export default {
  components: { SpinnerDialog },
  data() {
    return {
      username: {
        val: null,
        error: null,
      },
      password: {
        val: null,
        error: null,
      },

      error: null,
      isLoading: false,
      formValid: true,
    };
  },
  methods: {
    closeError() {
      this.error = null;
    },
    isFormValid() {
      this.formValid = true;
      this.checkUsername();
      this.checkPassword();
    },
    checkUsername() {
      this.username.error = null;
      if (!this.username.val || this.username.val == "") {
        this.formValid = false;
        this.username.error = "Username ไม่สามารถเว้นว่างได้";
      }
    },
    checkPassword() {
      this.password.error = null;
      if (!this.password.val || this.password.val == "") {
        this.formValid = false;
        this.password.error = "password ไม่สามารถเว้นว่างได้";
      }
    },
    async adminLogin() {
      this.isFormValid();

      if (!this.formValid) {
        return;
      }
      this.isLoading = true;
      const userRef = db.collection("users");
      const snapshot = await userRef
        .where("username", "==", this.username.val)
        .get()
        .catch((error) => {
          this.isLoading = false;
          console.error("Error getting documents: ", error);
        });
      let email = null;
      let username = null;
      let isAdmin = null;

      if (snapshot.size > 1) {
        this.isLoading = false;
        this.error = "found user more than 1 in Database";
        return;
      }

      snapshot.forEach((doc) => {
        email = doc.data().email;
        username = doc.data().username;
        isAdmin = doc.data().isAdmin;
      });

      if (!isAdmin) {
        this.isLoading = false;
        this.error = "Username not found";
        return;
      }

      if (!email || !username) {
        this.isLoading = false;
        this.error = "Username not found";
        return;
      }

      auth
        .signInWithEmailAndPassword(email, this.password.val)
        .then(() => {
          this.$router.replace({
            name: "quota-list",
          });
          this.isLoading = false;
        })
        .catch((error) => {
          this.isLoading = false;
          this.error = error.message;
        });
    },
  },
};
</script>

