    reqQuotaNotCc(state, getters) {
        const reqQuota = getters.reqQuota;
        let filtReqQuota = reqQuota.filter(
            (q) => q.reqResult.toLowerCase() !== "cancel"
        );
        filtReqQuota = filtReqQuota.filter(
            (q) => q.reqResult.toLowerCase() !== "reject"
        );
        return filtReqQuota;
    },

    getReqQuotaByResult: (state, getters) => (qResult) => {
        const reqQuota = getters.reqQuota;
        const filtReqQuota = reqQuota.filter(
            (q) => q.reqResult.toLowerCase() == qResult.toLowerCase()
        );
        return filtReqQuota;
    },

    reqQuotaResultStatus(state, getters) {
        const reqQuota = getters.reqQuota;
        const filtReqQuota = reqQuota.filter(
            (q) =>
            q.reqResult.toLowerCase() != "cancel" &&
            q.reqResult.toLowerCase() != "pending"
        );
        return filtReqQuota;
    },

    reqQuotaNoByStatus: (state, getters) => (qResult) => {
        return getters.getReqQuotaByResult(qResult).length;
    },

    getResQuotaNo: (state, getters) => (resPayload) => {
        if (isLogVisible()) {
            console.log(resPayload);
        }
        const quotaId = resPayload.quotaId;
        const reqId = resPayload.reqId;
        const reqRound = resPayload.reqRound;
        const resQuota = getters.resQuota;

        if (isLogVisible()) {
            console.log(resQuota);
        }

        // filter resQuota quota

        // get reserve Quota that match quota Id
        const filteredReqQuota = resQuota.filter(
            (q) => q.quota.id === quotaId && q.reqQutTime === reqRound
        );
        if (isLogVisible()) {
            console.log(filteredReqQuota);
        }

        // get request Quota that match request Id
        const selectedReqQuota = filteredReqQuota.find((req) => req.id === reqId);
        if (isLogVisible()) {
            console.log(selectedReqQuota);
        }

        // find index of selectedReqQuota in reserve Quota
        var index = filteredReqQuota.indexOf(selectedReqQuota);

        // get Quota Detail
        const the_quota = getters.getQuotaById(quotaId);
        if (isLogVisible()) {
            console.log(index);
            console.log(the_quota[`q${reqRound}Offer`]);
        }
        const qOffer = the_quota[`q${reqRound}Offer`];

        // calculate position
        const position = index + 1;
        if (position <= qOffer) {
            return 0;
        } else {
            return position - qOffer;
        }
    },

