<script>
// import SecItem from "./SecItem.vue";
import DataModal from "../../components/UI/DataModal.vue";
import FormValidation from "../../mixins/formValidation.js";
import QuotaRow from "./QuotaRow.vue";
import ConfirmModal from "../../components/UI/ConfirmModal.vue";
import SearchInput from "../../components/UI/SearchInput.vue";
import useVuelidate from "@vuelidate/core";
import { required, integer, minValue } from "@vuelidate/validators";
export default {
  setup() {
    return {
      v$: useVuelidate(),
    };
  },
  mixins: [FormValidation], // isNumber()
  components: { DataModal, QuotaRow, ConfirmModal, SearchInput },
  props: {
    yearNo: {
      required: true,
    },
    secDetail: {
      required: false,
      default: false,
    },
  },
  validations() {
    return {
      sec: {
        required,
      },
      group: {
        required,
      },
      q1Offer: {
        required,
        integer,
        minValueValue: minValue(0),
      },
      q2Offer: {
        integer,
        minValueValue: minValue(0),
      },
      q3Offer: {
        integer,
        minValueValue: minValue(0),
      },
      register: {
        integer,
        minValueValue: minValue(0),
      },
      remark: {},
      condition: {
        required,
      },
    };
  },

  data() {
    return {
      // UI
      editQuotaDia: false,
      formValid: true,
      editSuccess: false,
      deleteQuotaDia: false,
      error: null,

      // system
      offLink: null,
      quotaId: null,
      subName: null,
      subjectCode: null,
      q1Request: null,
      q1Accept: null,
      q2Request: null,
      q2Accept: null,
      q3Request: null,
      q3Accept: null,
      campus: null,
      condition: null,

      // user
      sec: null,
      group: null,
      q1Offer: null,
      q2Offer: null,
      q3Offer: null,
      register: null,
      remark: null,
    };
  },
  computed: {
    condCode() {
      return this.$store.getters["conditions/condCode"];
    },
    sections() {
      return this.$store.getters["sections/fullName"];
    },
    majorOffLinks() {
      return this.$store.getters["quota/getMajorOffLinks"];
    },
    LastSubject() {
      return this.$store.getters["subjects/getLastSubjectByOffLink"](
        this.offLink
      );
    },
    MaxYearsList() {
      return this.$store.getters["years/getMaxYears"](this.yearNo);
    },
    subNameCode() {
      return (
        this.LastSubject.name +
        " (" +
        this.getSubCode(this.MaxYearsList[0].name) +
        ", " +
        this.getSubCode(this.MaxYearsList[1].name) +
        ", " +
        this.getSubCode(this.MaxYearsList[2].name) +
        ", " +
        this.getSubCode(this.MaxYearsList[3].name) +
        ")"
      );
    },
  },
  methods: {
    getSubCode(year) {
      const sub = this.$store.getters["subjects/getSubjectByYearAndOffLink"]({
        year: year,
        offLink: this.offLink,
      });
      if (sub) {
        return sub.code;
      } else {
        return "-";
      }
    },
    editQuota(quotaId, offLink) {
      // set all
      this.offLink = offLink;

      const quotaData = this.$store.getters["quota/getQuotaById"](quotaId);
      console.log(quotaData);

      this.sec = quotaData.secId;
      this.group = quotaData.group;
      this.campus = quotaData.campus;
      this.q1Offer = quotaData.q1Offer;
      this.q2Offer = quotaData.q2Offer;
      this.q3Offer = quotaData.q3Offer;

      // 2
      this.quotaId = quotaData.id;
      this.register = quotaData.regNo;
      this.remark = quotaData.remark;
      this.condition = quotaData.condition;
      this.q1Request = quotaData.q1Request;
      this.q1Accept = quotaData.q1Accept;
      this.q2Request = quotaData.q2Request;
      this.q2Accept = quotaData.q2Accept;
      this.q3Request = quotaData.q3Request;
      this.q3Accept = quotaData.q3Accept;

      this.editQuotaDia = true;
    },
    closeQuotaDia() {
      this.editQuotaDia = false;
    },
    trydeleteQuota() {
      console.log(!this.q1Request);
      console.log(!this.q2Request);
      console.log(!this.q3Request);
      if (this.q1Request || this.q2Request || this.q3Request) {
        this.error =
          "ไม่สามารถลบ section นี้ได้ เนื่องจากมีนักศึกษาขอโควต้าเข้ามาแล้ว";
        return;
      }
      this.deleteQuotaDia = true;
    },
    async deleteQuota() {
      this.$store.dispatch("updateToast", {
        mode: "loading",
        show: true,
        message: "กำลังลบ Section..",
      });
      const submittedData = {
        id: this.quotaId,
      };
      this.closeQuotaDia();
      await this.$store.dispatch("quota/deleteQuota", submittedData);
      await this.$store.dispatch("clearToast");
      this.$store.dispatch("updateToast", {
        mode: "success",
        show: true,
        message: "ลบ Section เสร็จสิ้น",
      });
    },

    selectSec(val) {
      this.sec = val;
    },
    closeError() {
      this.error = null;
      this.formValid = true;
    },
    async submitData() {
      this.v$.$touch();
      if (this.v$.$error) return;

      this.$store.dispatch("updateToast", {
        mode: "loading",
        show: true,
        message: "กำลังทำการอัพเดตโควต้า",
      });
      const submittedData = {
        id: this.quotaId,
        secId: this.sec,
        group: this.group,
        campus: this.campus,
        q1Offer: this.q1Offer,
        q2Offer: this.q2Offer,
        q3Offer: this.q3Offer,
        regNo: this.register,
        remark: this.remark,
        condition: this.condition,
      };
      console.log(submittedData);
      this.editQuotaDia = false;
      await this.$store.dispatch("quota/updateQuota", submittedData);
      await this.$store.dispatch("clearToast");
      this.$store.dispatch("updateToast", {
        mode: "success",
        show: true,
        message: "อัพเดตโควต้าสำเร็จ",
      });
    },
  },
};
</script>

