                // } else if (theValue === "reject") {
                //     batch.update(quotaRef, {
                //         [`q${schedule.qRound}Request`]: firebase.firestore.FieldValue.increment(
                //             1
                //         ),
                //     });

                //     // update VueX
                //     storeQuota[`q${schedule.qRound}Request`] =
